def normalize_service_name(value):
    return " ".join((value or "").strip().split())


def split_service_catalogs_by_billing_type(apps, schema_editor):
    """Ensure service masters are unique by service name + billing type.

    Version 0003 created one catalog per service name because service names were unique.
    If legacy user services used the same name with different billing types, this
    migration creates the missing catalog rows and reconnects each user service to
    the catalog with the matching billing type.
    """

