    ServiceCatalog = apps.get_model("receipts", "ServiceCatalog")

    for service in RegisteredService.objects.select_related("catalog_service").all().order_by("id"):
        name = normalize_service_name(service.name) or f"Service {service.pk}"
        source_catalog = service.catalog_service
        matching_catalog = ServiceCatalog.objects.filter(name__iexact=name, billing_type=service.billing_type).order_by("id").first()
        if matching_catalog is None:
            matching_catalog = ServiceCatalog.objects.create(
                name=name,
                billing_type=service.billing_type,
                is_active=getattr(source_catalog, "is_active", True) if source_catalog else True,
                memo=getattr(source_catalog, "memo", "") if source_catalog else "",
                created_by_id=getattr(source_catalog, "created_by_id", None) if source_catalog else None,
            )
        if service.name != name or service.catalog_service_id != matching_catalog.pk:
            service.name = name
            service.catalog_service = matching_catalog
            service.save(update_fields=["name", "catalog_service"])

    canonical_by_key = {}
    for catalog in ServiceCatalog.objects.all().order_by("id"):
        name = normalize_service_name(catalog.name) or f"Service {catalog.pk}"
        key = (name.casefold(), catalog.billing_type)
        canonical = canonical_by_key.get(key)
        if canonical is None:
            canonical_by_key[key] = catalog
            updates = []
            if catalog.name != name:
                catalog.name = name
                updates.append("name")
            if updates:
                catalog.save(update_fields=updates + ["updated_at"])
            continue

        RegisteredService.objects.filter(catalog_service=catalog).update(catalog_service=canonical)
        if catalog.memo and not canonical.memo:
            canonical.memo = catalog.memo
            canonical.save(update_fields=["memo", "updated_at"])
        if catalog.is_active and not canonical.is_active:
            canonical.is_active = True
            canonical.save(update_fields=["is_active", "updated_at"])
        catalog.delete()


